{
  "mode": "method",
  "tests": [
    {
      "name": "add_wiproAllowed_field_default_false",
      "input": {
        "challenge": {
          "name": "New Challenge",
          "description": "A new challenge for testing.",
          "wiproAllowed": null
        }
      },
      "output": {
        "wiproAllowed": false
      },
      "notes": "Tests that the default value for wiproAllowed is False when not provided."
    },
    {
      "name": "add_wiproAllowed_field_true_for_past_challenges",
      "input": {
        "challenge": {
          "name": "Past Challenge",
          "description": "A past challenge for testing.",
          "createdAt": "2020-01-01T00:00:00Z"
        }
      },
      "output": {
        "wiproAllowed": true
      },
      "notes": "Tests that past challenges default wiproAllowed to True."
    },
    {
      "name": "add_wiproAllowed_field_explicit_true",
      "input": {
        "challenge": {
          "name": "Explicit True Challenge",
          "description": "Challenge with explicit wiproAllowed set to true.",
          "wiproAllowed": true
        }
      },
      "output": {
        "wiproAllowed": true
      },
      "notes": "Tests that wiproAllowed can be set to True explicitly."
    },
    {
      "name": "add_wiproAllowed_field_explicit_false",
      "input": {
        "challenge": {
          "name": "Explicit False Challenge",
          "description": "Challenge with explicit wiproAllowed set to false.",
          "wiproAllowed": false
        }
      },
      "output": {
        "wiproAllowed": false
      },
      "notes": "Tests that wiproAllowed can be set to False explicitly."
    },
    {
      "name": "add_wiproAllowed_field_missing",
      "input": {
        "challenge": {
          "name": "Missing Field Challenge",
          "description": "Challenge without wiproAllowed field."
        }
      },
      "output": {
        "wiproAllowed": false
      },
      "notes": "Tests that missing wiproAllowed field defaults to False."
    },
    {
      "name": "add_wiproAllowed_field_invalid_type",
      "input": {
        "challenge": {
          "name": "Invalid Type Challenge",
          "description": "Challenge with invalid wiproAllowed type.",
          "wiproAllowed": "not_a_boolean"
        }
      },
      "output": {
        "wiproAllowed": false
      },
      "notes": "Tests that invalid type for wiproAllowed defaults to False."
    },
    {
      "name": "add_wiproAllowed_field_edge_case_empty_string",
      "input": {
        "challenge": {
          "name": "Empty String Challenge",
          "description": "Challenge with wiproAllowed as an empty string.",
          "wiproAllowed": ""
        }
      },
      "output": {
        "wiproAllowed": false
      },
      "notes": "Tests that an empty string for wiproAllowed defaults to False."
    },
    {
      "name": "add_wiproAllowed_field_edge_case_boolean_string",
      "input": {
        "challenge": {
          "name": "Boolean String Challenge",
          "description": "Challenge with wiproAllowed as a boolean string.",
          "wiproAllowed": "true"
        }
      },
      "output": {
        "wiproAllowed": false
      },
      "notes": "Tests that a boolean string for wiproAllowed defaults to False."
    }
  ],
  "assumptions": "The challenge API correctly handles the wiproAllowed field as a boolean.",
